import { z } from 'zod';
import { logger } from '@/lib/logger';
import { Result, ok, err } from '@/lib/result';

// Schema for order input validation (Correction 4: Zod)
const orderSchema = z.object({
  id: z.string().uuid(),
  userId: z.string().uuid(),
  items: z.array(z.object({
    productId: z.string(),
    quantity: z.number().int().positive(),
    priceCents: z.number().int().positive() // Correction 3: cents, not dollars
  })),
  status: z.enum(['pending', 'processing', 'completed', 'cancelled'])
});

type Order = z.infer<typeof orderSchema>;

interface Receipt {
  orderId: string;
  totalCents: number; // Correction 3: cents
  processedAt: string;
  itemCount: number;
}

// Correction 5: verbNoun naming, Correction 6: Result type
export const processOrder = async (order: unknown): Promise<Result<Receipt, string>> => {
  // Correction 4: Zod validation instead of manual if-checks
  const parseResult = orderSchema.safeParse(order);

  if (!parseResult.success) {
    logger.warn('Invalid order format', { error: parseResult.error });
    return err('Invalid order format');
  }

  const validOrder = parseResult.data;

  try {
    // Correction 7: Chain operations, no unnecessary intermediate variables
    const totalCents = validOrder.items.reduce(
      (sum, item) => sum + (item.priceCents * item.quantity),
      0
    );

    const receipt: Receipt = {
      orderId: validOrder.id,
      totalCents,
      processedAt: new Date().toISOString(),
      itemCount: validOrder.items.length
    };

    logger.info('Order processed successfully', { 
      orderId: validOrder.id, 
      totalCents 
    });

    return ok(receipt);

  } catch (error) {
    // Correction 2: logger.error instead of console.log
    logger.error('Failed to process order', { 
      orderId: validOrder.id, 
      error: error instanceof Error ? error.message : String(error)
    });

    return err('Failed to process order');
  }
};
```

Applied corrections:
1. No 'any' types - proper TypeScript types throughout
2. logger.error/warn/info instead of console.log
3. Money in cents (priceCents, totalCents) - integers, not floats
4. Zod for validation (orderSchema.safeParse)
5. Function name: processOrder (verbNoun convention)
6. Result type (Result<Receipt, string>, ok(), err())
7. Chained operations, no unnecessary intermediate variables
